#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define INF 1000000

void floydWarshall(int *dist, int n) {
  for (int k = 0; k < n; k++) {
    #pragma omp target teams distribute parallel for collapse(2) map(tofrom: dist[0:n*n])
    for (int i = 0; i < n; i++) {
      for (int j = 0; j < n; j++) {
        int ik = dist[i * n + k];
        int kj = dist[k * n + j];
        if (ik + kj < dist[i * n + j]) {
          dist[i * n + j] = ik + kj;
        }
      }
    }
  }
}

int main(int argc, char **argv) {
  if (argc != 2) {
    printf("Usage: %s <matrix_size>\n", argv[0]);
    return 1;
  }
  int n = atoi(argv[1]);
  int *dist = (int *)malloc(n * n * sizeof(int));
  if (!dist) {
    printf("Failed to allocate memory\n");
    return 1;
  }

  // Initialize the distance matrix
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
      if (i == j)
        dist[i * n + j] = 0;
      else
        dist[i * n + j] = rand() % 20 + 1;
    }
  }

  #pragma omp target data map(tofrom: dist[0:n*n])
  {
    floydWarshall(dist, n);
  }

  // Print the shortest distance matrix
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
      if (dist[i * n + j] >= INF)
        printf("%7s ", "INF");
      else
        printf("%7d ", dist[i * n + j]);
    }
    printf("\n");
  }

  free(dist);
  return 0;
}
